import { MarksRegistry } from "../../../plot/MarksRegistry";
import { scatter_position, scatter_styles } from "./scatter-encode";
import { scatter_inner_position, scatter_inner_styles } from "./scatter-inner-encode";
import { scatter_outer_position, scatter_outer_styles } from "./scatter-outer-encode";

export function scatter_encode_collectors() {
    // TODO: Working on it
    // TODO: chartcategory.dotPlot = [scatter, bubble, geoscatter, geobubble];
    scatter_styles.call(this);
    scatter_position.call(this);

    scatter_outer_styles.call(this);
    scatter_outer_position.call(this);

    scatter_inner_styles.call(this);
    scatter_inner_position.call(this);

    const morphing = this.chart.systemConf.chart.plot.morph.enabled && this.chart.oldSeriesInfo;
    if (morphing) {
        MarksRegistry.get('scatter.morph').call(this);     // scatter_morph_collectors
    }
}